#include "nau7802.h"
#include <Wire.h>
#include <SparkFun_Qwiic_Scale_NAU7802_Arduino_Library.h>
static NAU7802 nau;
static int32_t _raw=0;static float _weight=0,_cal=1.0;static int32_t _tare=0;static unsigned long _l=0;
void nau7802_setup(){Wire.begin();if(!nau.begin()){Serial.println("[nau7802] Fail!");return;}nau.setSampleRate(NAU7802_SPS_320);Serial.println("[nau7802] OK");}
void nau7802_loop(){if(millis()-_l<100)return;_l=millis();if(nau.available()){_raw=nau.getReading();_weight=(_raw-_tare)*_cal;}}
float nau7802_get_weight(){return _weight;}
int32_t nau7802_get_raw(){return _raw;}
void nau7802_tare(){_tare=_raw;}
void nau7802_calibrate(float kw){_cal=kw/(_raw-_tare);}
